	@SuppressWarnings("unchecked")
	private void testCreateSurvey() throws Exception{
		
		JSONObject surveyjson = createBaseObject("survey", "survey/new");
		JSONObject properties = (JSONObject) surveyjson.get("properties");
		JSONObject attributes = (JSONObject) properties.get("smartAttributes");
		
		attributes.put("surveyDesign", surveyDesignKey);
		attributes.put("surveyUuid", UuidUtils.uuidToString(surveyUuid));
		
		attributes.put("id", surveyId);
		
		MissionJsonFeatureProcessor processor = processMissionJson(surveyjson);
		

		session.beginTransaction();
		try {
			DataLink link = session.createQuery("FROM DataLink WHERE conservationArea = :ca and providerId = :puuid and dataType = :datatype", DataLink.class) //$NON-NLS-1$
				.setParameter("ca",ca) //$NON-NLS-1$
				.setParameter("puuid", surveyUuid) //$NON-NLS-1$
				.setParameter("datatype", SurveyLinkDataType.SURVEY.getKey()) //$NON-NLS-1$
				.uniqueResult();
					
			if (link == null) throw new Exception("Survey not created");
					
			Survey survey = session.get(Survey.class, link.getSmartId());
			if (survey == null) throw new Exception("Survey not created");
			
			if (!survey.getId().equals(surveyId)) throw new Exception("Survey id not set correctly");
		}finally {
			session.getTransaction().rollback();
		}
	}
	
