	@SuppressWarnings("unchecked")
	private void testCreateMission() throws Exception{
		
		JSONObject missionjson = createBaseObject("mission", "mission/new");
		JSONObject properties = (JSONObject) missionjson.get("properties");
		JSONObject attributes = (JSONObject) properties.get("smartAttributes");
		
		
		attributes.put("survey", UuidUtils.uuidToString(surveyUuid));
		attributes.put("missionUuid", UuidUtils.uuidToString(missionUuid));
		
		attributes.put("missionId", missionId);
		attributes.put("comment", comment1);
		attributes.put("leader", UuidUtils.uuidToString(employee1.getUuid()));
		
		JSONArray members = new JSONArray();
		attributes.put("members", members);
		members.add(UuidUtils.uuidToString(employee1.getUuid()));
		members.add(UuidUtils.uuidToString(employee2.getUuid()));
		members.add(UuidUtils.uuidToString(employee3.getUuid()));
		
		
		MissionJsonFeatureProcessor processor = new MissionJsonFeatureProcessor();
		session.beginTransaction();
		try {
			processor.processFeature(missionjson, ca, session, Locale.getDefault());
			session.getTransaction().commit();
		
			System.out.println("WARNINGS:");
			for (String s : processor.getWarnings()) System.out.println(s);
			System.out.println("END WARNINGS:");
		}catch (Exception ex) {
			throw ex;
		}
		

		session.beginTransaction();
		try {
			Mission added = processor.getModifiedFeatures().iterator().next();
			Mission toTest = session.get(Mission.class, added.getUuid());
			
			if (toTest == null) throw new Exception("Mission not created");
			
			if (!toTest.getId().equals(missionId)) throw new Exception("Mission attributes not set correctly");
			if (!toTest.getComment().equals(comment1)) throw new Exception("Mission attributes not set correctly");
			if (!toTest.getLeader().getMember().equals(employee1)) throw new Exception("Mission leader not set correctly");
			Set<Employee> mmembers = toTest.getMembers().stream().map(e->e.getMember()).collect(Collectors.toSet());
			if (mmembers.size() != 3) throw new Exception("Mission attributes not set correctly");
			if (!mmembers.contains(employee1)) throw new Exception("Mission attributes not set correctly");
			if (!mmembers.contains(employee2)) throw new Exception("Mission attributes not set correctly");
			if (!mmembers.contains(employee3)) throw new Exception("Mission attributes not set correctly");
		
		}finally {
			session.getTransaction().rollback();
		}

	}
	
	
	
	@SuppressWarnings("unchecked")
	private void testUpdateMission() throws Exception{
		
		JSONObject missionjson = createBaseObject("mission", "mission");
		JSONObject properties = (JSONObject) missionjson.get("properties");
		JSONObject attributes = (JSONObject) properties.get("smartAttributes");
		
		
		attributes.put("survey", UuidUtils.uuidToString(surveyUuid));
		attributes.put("missionUuid", UuidUtils.uuidToString(missionUuid));
		
		attributes.put("missionId", missionId2);
		attributes.put("comment", comment2);
		attributes.put("leader", UuidUtils.uuidToString(employee3.getUuid()));
		
		JSONArray members = new JSONArray();
		attributes.put("members", members);
		members.add(UuidUtils.uuidToString(employee3.getUuid()));
		members.add(UuidUtils.uuidToString(employee5.getUuid()));
		
		MissionJsonFeatureProcessor processor = processMissionJson(missionjson);

		session.beginTransaction();
		try {
			Mission added = processor.getModifiedFeatures().iterator().next();
			Mission toTest = session.get(Mission.class, added.getUuid());
			
			if (toTest == null) throw new Exception("Mission not created");
			
			if (!toTest.getId().equals(missionId2)) throw new Exception("Mission attributes not set correctly");
			if (!toTest.getComment().equals(comment2)) throw new Exception("Mission attributes not set correctly");
			if (!toTest.getLeader().getMember().equals(employee3)) throw new Exception("Mission leader not set correctly");
			Set<Employee> mmembers = toTest.getMembers().stream().map(e->e.getMember()).collect(Collectors.toSet());
			if (mmembers.size() != 2) throw new Exception("Mission attributes not set correctly");
			if (!mmembers.contains(employee3)) throw new Exception("Mission attributes not set correctly");
			if (!mmembers.contains(employee5)) throw new Exception("Mission attributes not set correctly");
			
		
		}finally {
			session.getTransaction().rollback();
		}
		
		
		// ----------- TEST INVALID LEADER --------------
		attributes.clear();
		attributes.put("surveyUuid", UuidUtils.uuidToString(surveyUuid));
		attributes.put("missionUuid", UuidUtils.uuidToString(missionUuid));
		
		attributes.put("leader", UuidUtils.uuidToString(employee1.getUuid()));
		
		processor = new MissionJsonFeatureProcessor();
		boolean fail = false;
		session.beginTransaction();
		try {
			processor.processFeature(missionjson, ca, session, Locale.getDefault());
			session.getTransaction().commit();
			fail = true;
		}catch (Exception ex) {
			session.getTransaction().rollback();
		}
		if (fail) throw new Exception("Update should have failed but didn't");
		
		// ----------- TEST INVALID EMPLOYEES --------------
		attributes.clear();
		attributes.put("surveyUuid", UuidUtils.uuidToString(surveyUuid));
		attributes.put("missionUuid", UuidUtils.uuidToString(missionUuid));
			
		members = new JSONArray();
		attributes.put("members", members);
		members.add(UuidUtils.uuidToString(employee4.getUuid()));
		members.add(UuidUtils.uuidToString(employee5.getUuid()));
				
		processor = new MissionJsonFeatureProcessor();
		fail = false;
		session.beginTransaction();
		try {
			processor.processFeature(missionjson, ca, session, Locale.getDefault());
			session.getTransaction().commit();
			fail = true;
		}catch (Exception ex) {
			session.getTransaction().rollback();
		}
		if (fail) throw new Exception("Update should have failed but didn't");

		// ----------- TEST LEADER --------------
		attributes.clear();
		attributes.put("surveyUuid", UuidUtils.uuidToString(surveyUuid));
		attributes.put("missionUuid", UuidUtils.uuidToString(missionUuid));
					
		attributes.put("leader", UuidUtils.uuidToString(employee5.getUuid()));

		processor = new MissionJsonFeatureProcessor();
		fail = false;
		session.beginTransaction();
		try {
			processor.processFeature(missionjson, ca, session, Locale.getDefault());
			session.getTransaction().commit();
		}catch (Exception ex) {
			throw ex;
		}
		session.beginTransaction();
		try {
			Mission added = processor.getModifiedFeatures().iterator().next();
			Mission toTest = session.get(Mission.class, added.getUuid());
			if (toTest == null) throw new Exception("Mission not created");
			if (!toTest.getLeader().getMember().equals(employee5)) throw new Exception("Mission leader not set correctly");
		}finally {
			session.getTransaction().rollback();
		}
	}

	private MissionJsonFeatureProcessor processMissionJson(JSONObject missionjson) throws Exception {
		MissionJsonFeatureProcessor processor = new MissionJsonFeatureProcessor();
		session.beginTransaction();
		try {
			processor.processFeature(missionjson, ca, session, Locale.getDefault());
			session.getTransaction().commit();
		
			System.out.println("WARNINGS:");
			for (String s : processor.getWarnings()) System.out.println(s);
			System.out.println("END WARNINGS:");
		}catch (Exception ex) {
			session.getTransaction().rollback();
			throw ex;
		}
		return processor;
	}

	@SuppressWarnings("unchecked")
	private JSONObject createBaseObject(String dataType, String featuretype) {
		JSONObject missionjson = new JSONObject();
		missionjson.put("type",  "Feature");
		
		JSONObject geometry = new JSONObject();
		geometry.put("type", "Point");
		JSONArray coords = new JSONArray();
		coords.add(-123.34817573);
		coords.add(48.45632695);
		geometry.put("coordinates", coords);
		
		missionjson.put("geometry",  geometry);
		
		
		JSONObject properties = new JSONObject();
		missionjson.put("properties",  properties);
		
		properties.put("dateTime", "2021-12-03T15:14:13");
		properties.put("smartDataType", dataType);
		properties.put("smartFeatureType", featuretype);
		
		JSONObject attributes = new JSONObject();
		properties.put("smartAttributes", attributes);
		
		
		return missionjson;
	}

	@SuppressWarnings("unchecked")
	private void testEndMission() throws Exception{
		JSONObject missionjson = createBaseObject("mission", "mission/end");
		JSONObject properties = (JSONObject) missionjson.get("properties");
		JSONObject attributes = (JSONObject) properties.get("smartAttributes");
		
		properties.put("dateTime", "2021-12-03T17:16:15");

		attributes.put("missionUuid", UuidUtils.uuidToString(missionUuid));
		
		MissionJsonFeatureProcessor processor = processMissionJson(missionjson);
		Mission added = processor.getModifiedFeatures().iterator().next();
		
		session.beginTransaction();
		try {
			Mission m = session.get(Mission.class, added.getUuid());
			if (!m.getMissionDays().get(0).getEndTime().equals(LocalTime.of(17,16,15))) throw new Exception("Mission not ended correctly.");
		}finally {
			session.getTransaction().rollback();
		}
	}
	
